use crossterm::{
    cursor,
    event::{self, Event, KeyCode, KeyEvent, KeyEventKind},
    execute, queue,
    style::{self, Stylize},
    terminal::{self, ClearType},
};
use std::collections::VecDeque;
use std::io::{self, Write};
use std::time::{Duration, Instant};

const TICK: Duration = Duration::from_millis(120);

#[derive(Clone, Copy, PartialEq)]
struct Pos {
    x: u16,
    y: u16,
}

#[derive(Clone, Copy, PartialEq)]
enum Dir {
    Up,
    Down,
    Left,
    Right,
}

impl Dir {
    fn opposite(self) -> Self {
        match self {
            Dir::Up => Dir::Down,
            Dir::Down => Dir::Up,
            Dir::Left => Dir::Right,
            Dir::Right => Dir::Left,
        }
    }
}

struct Game {
    width: u16,
    height: u16,
    snake: VecDeque<Pos>,
    dir: Dir,
    food: Pos,
    score: u32,
    over: bool,
}

impl Game {
    fn new(width: u16, height: u16) -> Self {
        let cx = width / 2;
        let cy = height / 2;
        let mut snake = VecDeque::new();
        snake.push_back(Pos { x: cx, y: cy });
        snake.push_back(Pos { x: cx - 1, y: cy });
        snake.push_back(Pos { x: cx - 2, y: cy });
        let mut g = Game {
            width,
            height,
            snake,
            dir: Dir::Right,
            food: Pos { x: 0, y: 0 },
            score: 0,
            over: false,
        };
        g.place_food();
        g
    }

    fn place_food(&mut self) {
        let seed = (self.score as u64)
            .wrapping_mul(6364136223846793005)
            .wrapping_add(self.snake[0].x as u64 * 31 + self.snake[0].y as u64 * 37)
            .wrapping_add(
                std::time::SystemTime::now()
                    .duration_since(std::time::UNIX_EPOCH)
                    .unwrap_or_default()
                    .as_nanos() as u64,
            );
        let inner_w = (self.width - 2) as u64;
        let inner_h = (self.height - 2) as u64;
        let mut x;
        let mut y;
        let mut i = 0u64;
        loop {
            let h = seed.wrapping_add(i).wrapping_mul(6364136223846793005);
            x = (h % inner_w) as u16 + 1;
            y = ((h / inner_w) % inner_h) as u16 + 1;
            if !self.snake.iter().any(|p| p.x == x && p.y == y) {
                break;
            }
            i += 1;
        }
        self.food = Pos { x, y };
    }

    fn tick(&mut self) {
        if self.over {
            return;
        }
        let head = self.snake[0];
        let next = match self.dir {
            Dir::Up => Pos { x: head.x, y: head.y.wrapping_sub(1) },
            Dir::Down => Pos { x: head.x, y: head.y + 1 },
            Dir::Left => Pos { x: head.x.wrapping_sub(1), y: head.y },
            Dir::Right => Pos { x: head.x + 1, y: head.y },
        };

        if next.x == 0 || next.x >= self.width - 1 || next.y == 0 || next.y >= self.height - 1 {
            self.over = true;
            return;
        }
        if self.snake.iter().any(|p| *p == next) {
            self.over = true;
            return;
        }

        self.snake.push_front(next);

        if next == self.food {
            self.score += 1;
            self.place_food();
        } else {
            self.snake.pop_back();
        }
    }

    fn draw(&self, stdout: &mut io::Stdout) -> io::Result<()> {
        queue!(stdout, cursor::MoveTo(0, 0))?;

        for y in 0..self.height {
            for x in 0..self.width {
                let pos = Pos { x, y };
                let ch = if x == 0 || x == self.width - 1 || y == 0 || y == self.height - 1 {
                    style::PrintStyledContent("#".dark_grey())
                } else if pos == self.snake[0] {
                    style::PrintStyledContent("@".green())
                } else if self.snake.iter().skip(1).any(|p| *p == pos) {
                    style::PrintStyledContent("o".green())
                } else if pos == self.food {
                    style::PrintStyledContent("*".red())
                } else {
                    style::PrintStyledContent(" ".stylize())
                };
                queue!(stdout, ch)?;
            }
            if y < self.height - 1 {
                queue!(stdout, cursor::MoveToNextLine(1))?;
            }
        }

        let score_text = format!(" Score: {} ", self.score);
        queue!(
            stdout,
            cursor::MoveTo(2, 0),
            style::PrintStyledContent(score_text.as_str().white().bold())
        )?;

        if self.over {
            let msg = " GAME OVER — press 'q' to quit, 'r' to restart ";
            let mx = self.width.saturating_sub(msg.len() as u16) / 2;
            let my = self.height / 2;
            queue!(
                stdout,
                cursor::MoveTo(mx, my),
                style::PrintStyledContent(msg.white().bold().on_dark_red())
            )?;
        }

        stdout.flush()
    }
}

fn main() -> io::Result<()> {
    let mut stdout = io::stdout();
    terminal::enable_raw_mode()?;
    execute!(
        stdout,
        terminal::EnterAlternateScreen,
        cursor::Hide,
        terminal::Clear(ClearType::All)
    )?;

    let (cols, rows) = terminal::size()?;
    let width = cols.min(60);
    let height = rows.min(30);
    let mut game = Game::new(width, height);

    let result = run(&mut stdout, &mut game, width, height);

    execute!(stdout, cursor::Show, terminal::LeaveAlternateScreen)?;
    terminal::disable_raw_mode()?;
    result
}

fn run(stdout: &mut io::Stdout, game: &mut Game, width: u16, height: u16) -> io::Result<()> {
    let mut last_tick = Instant::now();

    loop {
        let timeout = TICK.saturating_sub(last_tick.elapsed());
        if event::poll(timeout)? {
            if let Event::Key(KeyEvent { code, kind: KeyEventKind::Press, .. }) = event::read()? {
                match code {
                    KeyCode::Char('q') | KeyCode::Esc => return Ok(()),
                    KeyCode::Char('r') if game.over => {
                        *game = Game::new(width, height);
                        execute!(stdout, terminal::Clear(ClearType::All))?;
                    }
                    KeyCode::Up if game.dir != Dir::Down => game.dir = Dir::Up,
                    KeyCode::Down if game.dir != Dir::Up => game.dir = Dir::Down,
                    KeyCode::Left if game.dir != Dir::Right => game.dir = Dir::Left,
                    KeyCode::Right if game.dir != Dir::Left => game.dir = Dir::Right,
                    _ => {}
                }
            }
        }

        if last_tick.elapsed() >= TICK {
            game.tick();
            last_tick = Instant::now();
        }
        game.draw(stdout)?;
    }
}

